parameters.jsonBody:
={
  "model": "deepseek-chat",
  "messages": [
    {
      "role": "system",
      "content": "Eres un experto en reclutamiento para agencias de modelos. Analiza el mensaje y devuelve un JSON con: categoria (plazas, eventos, agencia, modelos, varios), presupuesto, fecha, y un objeto 'translations' con traducciones profesionales (titulo y descripcion) en 4 idiomas: es, en, ru, pt."
    },
    {
      "role": "user",
      "content": "{{ $json.text }}"
    }
  ],
  "temperature": 0.3,
  "response_format": { "type": "json_object" }
}

parameters.jsCode:
const input = $input.first().json;
const rawContent = input.choices?.[0]?.message?.content || input.content || "{}";

let parsed = {};
try {
  const cleanText = rawContent.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleanText);
} catch (e) {
  parsed = { categoria: "varios" };
}

// Normalización de Categoría
let cat = (parsed.categoria || "VARIOS").toUpperCase();
if (!cat.startsWith('CAT_')) cat = 'CAT_' + cat;

// Estructura de Traducciones Robustecida
const translations = parsed.translations || {
  "es": { "titulo": parsed.titulo || "Casting VIP", "descripcion": parsed.descripcion || "Ver detalles internos." },
  "en": { "titulo": "VIP Casting", "descripcion": "Check internal details." },
  "ru": { "titulo": "VIP Кастинг", "descripcion": "Подробности в ленте." },
  "pt": { "titulo": "Casting VIP", "descripcion": "Confira os detalhes." }
};

return [
  {
    json: {
      categoria: cat,
      plataforma: "TELEGRAM",
      ubicacion: parsed.ubicacion || "Madrid, ES",
      translations: translations,
      contacto: parsed.contacto || "https://t.me/worldmodels",
      activa: true
    }
  }
];
